var requestDuration = prometheus.NewHistogramVec(prometheus.HistogramOpts{
    Name:    "http_request_duration_seconds",
    Help:    "HTTP request latency with trace exemplars.",
    Buckets: prometheus.DefBuckets,
}, []string{"route"})

func recordWithExemplar(ctx context.Context, route string, d float64) {
    span := trace.SpanFromContext(ctx)
    obs := requestDuration.With(prometheus.Labels{"route": route})
    if eo, ok := obs.(prometheus.ExemplarObserver); ok {
        eo.ObserveWithExemplar(d, prometheus.Labels{
            "traceID": span.SpanContext().TraceID().String(),
        })
        return
    }
    obs.Observe(d)
}

import (
    "github.com/prometheus/client_golang/prometheus"
    "github.com/prometheus/client_golang/prometheus/promauto"
)

var requestDuration = promauto.NewHistogramVec(prometheus.HistogramOpts{
    Name:    "http_request_duration_seconds",
    Buckets: prometheus.DefBuckets,
}, []string{"method", "status"})

// ObserveWithExemplar attaches a trace_id correlation ID to the metric sample.
func recordRequest(method, status, traceID string, duration float64) {
    requestDuration.WithLabelValues(method, status).(prometheus.ExemplarObserver).
        ObserveWithExemplar(duration, prometheus.Labels{"trace_id": traceID})
}

